import { useState, useEffect, useRef } from "react";
import { ThumbsUp, ThumbsDown, CheckCircle2, Send, X, Loader2 } from "lucide-react";
import { useLocation } from "wouter";

function sanitizeFormText(value: string) {
  return value
    .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, "")
    .replace(/[<>]/g, "")
    .trim();
}

function pathToTitle(path: string): string {
  return path
    .replace(/^\//, "")
    .split("-")
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ") || "Home";
}

export default function FeedbackWidget() {
  const [location] = useLocation();
  const storageKey = `ec_feedback:${location}`;
  const [vote, setVote] = useState<"up" | "down" | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [comment, setComment] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [sending, setSending] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    const stored = localStorage.getItem(storageKey);
    if (stored === "up" || stored === "down") setVote(stored);
  }, [storageKey]);

  useEffect(() => {
    if (showForm) {
      setTimeout(() => textareaRef.current?.focus(), 50);
    }
  }, [showForm]);

  async function sendFeedback(v: "up" | "down", text: string) {
    const calculator = pathToTitle(location);
    try {
      await fetch("/api/feedback", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ calculator, path: location, vote: v, comment: text }),
      });
    } catch {
      // silently ignore - network error shouldn't block the UI
    }
  }

  async function handleVote(v: "up" | "down") {
    if (vote) return;
    setVote(v);
    localStorage.setItem(storageKey, v);
    if (v === "up") {
      sendFeedback("up", "");
    } else {
      setShowForm(true);
    }
  }

  async function handleSubmitComment(e: React.FormEvent) {
    e.preventDefault();
    setSending(true);
    await sendFeedback("down", sanitizeFormText(comment));
    setSending(false);
    setShowForm(false);
    setSubmitted(true);
  }

  function handleSkip() {
    sendFeedback("down", "");
    setShowForm(false);
    setSubmitted(true);
  }

  if (vote === "up") {
    return (
      <div className="ec-feedback flex items-center justify-between bg-muted/40 border border-border rounded-xl px-5 py-3.5 mt-8">
        <p className="text-sm font-medium text-muted-foreground">Was this calculator helpful?</p>
        <span className="flex items-center gap-1.5 text-sm font-semibold text-emerald-600 dark:text-emerald-400">
          <CheckCircle2 className="w-4 h-4" />
          Great - thanks for the feedback!
        </span>
      </div>
    );
  }

  if (vote === "down" && submitted) {
    return (
      <div className="ec-feedback flex items-center justify-between bg-muted/40 border border-border rounded-xl px-5 py-3.5 mt-8">
        <p className="text-sm font-medium text-muted-foreground">Was this calculator helpful?</p>
        <span className="flex items-center gap-1.5 text-sm font-semibold text-muted-foreground">
          <CheckCircle2 className="w-4 h-4 text-emerald-500" />
          Noted - we'll keep improving!
        </span>
      </div>
    );
  }

  if (vote === "down" && showForm) {
    return (
      <div className="ec-feedback bg-muted/40 border border-border rounded-xl px-5 py-4 mt-8">
        <div className="flex items-center justify-between mb-3">
          <p className="text-sm font-semibold text-foreground">
            What could be better? <span className="text-muted-foreground font-normal">(optional)</span>
          </p>
          <button
            onClick={handleSkip}
            className="text-muted-foreground hover:text-foreground transition-colors p-1 rounded-md hover:bg-muted"
            aria-label="Skip feedback"
          >
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
        <form onSubmit={handleSubmitComment} className="space-y-3">
          <textarea
            ref={textareaRef}
            value={comment}
            onChange={(e) => setComment(e.target.value.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F<>]/g, ""))}
            placeholder="e.g. Missing an input, result seems off, hard to use on mobile-"
            rows={3}
            className="w-full text-sm bg-background border border-input rounded-lg px-3 py-2.5 text-foreground placeholder:text-muted-foreground/60 focus:outline-none focus:ring-2 focus:ring-primary/30 focus:border-primary transition-all resize-none leading-relaxed"
          />
          <div className="flex items-center gap-2 justify-end">
            <button
              type="button"
              onClick={handleSkip}
              disabled={sending}
              className="text-xs text-muted-foreground hover:text-foreground transition-colors px-3 py-1.5 rounded-lg hover:bg-muted disabled:opacity-50"
            >
              Skip
            </button>
            <button
              type="submit"
              disabled={sending}
              className="inline-flex items-center gap-1.5 text-xs font-semibold bg-primary text-primary-foreground px-3 py-1.5 rounded-lg hover:opacity-90 active:opacity-80 transition-opacity shadow-sm disabled:opacity-60"
            >
              {sending ? (
                <><Loader2 className="w-3 h-3 animate-spin" /> Sending-</>
              ) : (
                <><Send className="w-3 h-3" /> Send feedback</>
              )}
            </button>
          </div>
        </form>
      </div>
    );
  }

  return (
    <div className="ec-feedback flex items-center justify-between bg-muted/40 border border-border rounded-xl px-5 py-3.5 mt-8">
      <p className="text-sm font-medium text-muted-foreground">Was this calculator helpful?</p>
      <div className="flex items-center gap-2">
        <button
          onClick={() => handleVote("up")}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-border bg-card hover:border-emerald-400 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors text-muted-foreground text-sm font-medium"
          aria-label="Mark as helpful"
        >
          <ThumbsUp className="w-3.5 h-3.5" /> Yes
        </button>
        <button
          onClick={() => handleVote("down")}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-border bg-card hover:border-red-400 hover:text-red-500 dark:hover:text-red-400 transition-colors text-muted-foreground text-sm font-medium"
          aria-label="Mark as not helpful"
        >
          <ThumbsDown className="w-3.5 h-3.5" /> No
        </button>
      </div>
    </div>
  );
}


